def validate(args, output):
    n = args[0]
    k = args[1]
    if not isinstance(output, str):
        return False
    total = k ** n
    expected_len = total + (n - 1)
    if len(output) != expected_len:
        return False
    for ch in output:
        if not ('0' <= ch <= '9'):
            return False
        if int(ch) >= k:
            return False
    seen = set()
    for i in range(len(output) - n + 1):
        seen.add(output[i:i + n])
    return len(seen) == total

