function validate(args, output) {
    const n = args[0];
    const k = args[1];
    if (typeof output !== 'string') return false;
    const total = Math.pow(k, n);
    const expectedLen = total + (n - 1);
    if (output.length !== expectedLen) return false;
    for (const ch of output) {
        if (!(ch >= '0' && ch <= '9')) return false;
        if (Number(ch) >= k) return false;
    }
    const seen = new Set();
    for (let i = 0; i <= output.length - n; i++) {
        seen.add(output.slice(i, i + n));
    }
    return seen.size === total;
}

