solutions.javascript:
var crackSafe = function(n, k) {
    if (n === 1) {
        let s = '';
        for (let d = 0; d < k; d++) s += d;
        return s;
    }
    const seen = new Set();
    const result = [];
    const start = '0'.repeat(n - 1);
    function dfs(node) {
        for (let d = 0; d < k; d++) {
            const edge = node + d;
            if (!seen.has(edge)) {
                seen.add(edge);
                dfs(edge.slice(1));
                result.push(String(d));
            }
        }
    }
    dfs(start);
    return result.join('') + start;
};
